class Solution:
    def minSteps(self, n: int) -> int:
        def dp(i, j):
            if i == n:
                return 0
            if (i, j) in memo:
                return memo[(i, j)]
            if i < j:
                return float('inf')
            res = float('inf')
            if i > 0:
                res = min(res, 1 + dp(i + j, j))
            if i > j:
                res = min(res, 1 + dp(i + i, i))
            memo[(i, j)] = res
            return res
        memo = {}
        return dp(1, 1)
```
